def validation_error(arrival, sheets):
    if arrival < 0:
        return "到着時刻は0以上"
    if sheets < 1:
        return "枚数は1〜40"
    if sheets > 40:
        return "枚数は1〜40"
    return ""


def keep_valid_jobs(jobs):
    valid = []
    invalid = []
    previous_arrival = 0
    has_previous = False
    descending = False
    for job in jobs:
        if has_previous:
            if job[1] < previous_arrival:
                descending = True
        previous_arrival = job[1]
        has_previous = True
    if descending:
        for job in jobs:
            invalid.append([job[0], "到着時刻は非減少順"])
        return [valid, invalid]
    count = 0
    for job in jobs:
        count = count + 1
        if count > 10:
            invalid.append([job[0], "依頼数は10件以下"])
        else:
            error = validation_error(job[1], job[2])
            if error == "":
                valid.append(job)
            else:
                invalid.append([job[0], error])
    return [valid, invalid]


def fifo_order(jobs):
    ordered = []
    for job in jobs:
        ordered.append(job)
    return ordered


def ceil_divide(value, divisor):
    return (value + divisor - 1) // divisor


def simulate_fifo(ordered_jobs, speed):
    free_at = 0
    results = []
    for job in ordered_jobs:
        if job[1] > free_at:
            start = job[1]
        else:
            start = free_at
        finish = start + ceil_divide(job[2], speed)
        wait = start - job[1]
        results.append([job[0], start, finish, wait])
        free_at = finish
    return results


def average_wait(results):
    if len(results) == 0:
        return 0
    total = 0
    for row in results:
        total = total + row[3]
    return total / len(results)


